import { parseQueryString, stringifyQueryString } from '../src/queryString'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("parse basic", JSON.stringify(parseQueryString("a=1&b=2")), "{\"a\":\"1\",\"b\":\"2\"}")
await check("parse with ?", parseQueryString("?x=1")["x"], "1")
await check("parse empty", JSON.stringify(parseQueryString("")), "{}")
await check("parse encoded", parseQueryString("q=hello%20world")["q"], "hello world")
await check("parse no value", parseQueryString("flag")["flag"], "")
await check("stringify basic", stringifyQueryString({a:"1",b:"2"}), "a=1&b=2")
await check("stringify encodes spaces", stringifyQueryString({q:"hello world"}), "q=hello%20world")
await check("stringify empty value", stringifyQueryString({flag:""}), "flag")
await check("roundtrip", JSON.stringify(parseQueryString(stringifyQueryString({a:"1",b:"hello world"}))), "{\"a\":\"1\",\"b\":\"hello world\"}")
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
